void solve(int CASE)
{
	ll n, a, b; cin >> n >> a >> b;
	ll g = Math::gcd(a, b);
	fa(i, 1, n) {
		ll c; cin >> c;
      	// 枚举可能解，范围 [c, c + 1e3 - 1]
		for (ll C = (c + g - 1) / g * g; ; C += g) {
			ll x0, y0; // 特解
			Math::exgcd(a, b, x0, y0);
			x0 *= C / g, y0 *= C / g;
			/* 通解
			* x = x0 + K * b / g;
			* y = y0 - K * a / g;
			*/
			ll dx = b / g, dy = a / g;
			ll x1 = (x0 % dx + dx) % dx; // x 最小非负整数解
			ll y1 = (C - a * x1) / b;    // x 对应的 y 解
			if (y1 >= 0) {
				cout << x1 << ' ' << y1 << endl;
				break;
			}
		}
	}
	return;
}
